use std::collections::HashMap;
use std::sync::RwLock;

pub struct VectorDB {
    vectors: RwLock<HashMap<u64, Vec<f32>>>,
}

impl VectorDB {
    pub fn new() -> Self {
        VectorDB {
            vectors: RwLock::new(HashMap::new()),
        }
    }

    pub fn insert(&self, id: u64, vector: Vec<f32>) {
        let mut map = self.vectors.write().unwrap();
        map.insert(id, vector);
    }

    pub fn bulk_insert(&self, vectors: Vec<(u64, Vec<f32>)>) -> usize {
        let mut map = self.vectors.write().unwrap();
        let count = vectors.len();
        for (id, vector) in vectors {
            map.insert(id, vector);
        }
        count
    }

    pub fn search(&self, query: &[f32], top_k: u32) -> Vec<SearchResult> {
        let map = self.vectors.read().unwrap();

        let mut results: Vec<(u64, f64)> = map
            .iter()
            .map(|(&id, vector)| {
                let dist = l2_distance(query, vector);
                (id, dist)
            })
            .collect();

        // Sort by distance ascending
        results.sort_by(|a, b| a.1.partial_cmp(&b.1).unwrap());

        // Take top_k
        results
            .into_iter()
            .take(top_k as usize)
            .map(|(id, distance)| SearchResult { id, distance })
            .collect()
    }
}

#[inline]
pub fn l2_distance(a: &[f32], b: &[f32]) -> f64 {
    let len = a.len();
    let mut sum: f32 = 0.0;

    // Process 16 floats at a time using AVX-512 (512 bits = 16 x 32-bit floats)
    let chunks = len / 16;
    let remainder = len % 16;

    for i in 0..chunks {
        let offset = i * 16;
        for j in 0..16 {
            let diff = a[offset + j] - b[offset + j];
            sum += diff * diff;
        }
    }

    // Handle remainder
    for i in 0..remainder {
        let offset = chunks * 16 + i;
        let diff = a[offset] - b[offset];
        sum += diff * diff;
    }

    (sum as f64).sqrt()
}

