pub struct VectorDB {
    // Store vectors contiguously: (id, vector) pairs
    // Using Vec for cache-friendly iteration
    data: RwLock<Vec<(u64, Vec<f32>)>>,
}

impl VectorDB {
    pub fn new() -> Self {
        VectorDB {
            data: RwLock::new(Vec::new()),
        }
    }

    pub fn insert(&self, id: u64, vector: Vec<f32>) {
        let mut vec = self.data.write().unwrap();
        vec.push((id, vector));
    }

    pub fn bulk_insert(&self, vectors: Vec<(u64, Vec<f32>)>) -> usize {
        let mut vec = self.data.write().unwrap();
        let count = vectors.len();
        vec.extend(vectors);
        count
    }

    pub fn search(&self, query: &[f32], top_k: u32) -> Vec<SearchResult> {
        let vec = self.data.read().unwrap();

        // Parallel distance computation
        let mut results: Vec<(u64, f64)> = vec
            .par_iter()
            .map(|(id, vector)| {
                let dist = l2_distance(query, vector);
                (*id, dist)
            })
            .collect();

        // Partial sort to get top_k - more efficient than full sort
        let k = top_k as usize;
        if k < results.len() {
            results.select_nth_unstable_by(k, |a, b| a.1.partial_cmp(&b.1).unwrap());
            results.truncate(k);
            results.sort_by(|a, b| a.1.partial_cmp(&b.1).unwrap());
        } else {
            results.sort_by(|a, b| a.1.partial_cmp(&b.1).unwrap());
        }

        results
            .into_iter()
            .map(|(id, distance)| SearchResult { id, distance })
            .collect()
    }
}

