use crate::api::SearchResult;
use crate::distance::{l2_distance, l2_distance_squared};
use rayon::prelude::*;
use std::collections::BinaryHeap;
use std::sync::RwLock;

// Store vectors in a flat array for better cache locality
// IDs and vectors stored separately (Structure of Arrays pattern)
pub struct VectorDB {
    ids: RwLock<Vec<u64>>,
    vectors: RwLock<Vec<f32>>, // flattened: [v0_0, v0_1, ..., v0_127, v1_0, ...]
}

impl VectorDB {
    pub fn new() -> Self {
        VectorDB {
            ids: RwLock::new(Vec::new()),
            vectors: RwLock::new(Vec::new()),
        }
    }

    pub fn insert(&self, id: u64, vector: Vec<f32>) {
        let mut ids = self.ids.write().unwrap();
        let mut vectors = self.vectors.write().unwrap();
        ids.push(id);
        vectors.extend(vector);
    }

    pub fn bulk_insert(&self, vectors: Vec<(u64, Vec<f32>)>) -> usize {
        let mut ids = self.ids.write().unwrap();
        let mut vecs = self.vectors.write().unwrap();
        let count = vectors.len();
        for (id, v) in vectors {
            ids.push(id);
            vecs.extend(v);
        }
        count
    }

    pub fn search(&self, query: &[f32], top_k: u32) -> Vec<SearchResult> {
        let ids = self.ids.read().unwrap();
        let vectors = self.vectors.read().unwrap();

        let n = ids.len();
        if n == 0 {
            return Vec::new();
        }

        let k = top_k as usize;

        // Use a max-heap to keep track of top-k smallest distances
        // We store (distance, id) and keep heap size at k
        // When heap is full and we find a smaller distance, pop max and push new
        let mut heap: BinaryHeap<(OrderedFloat, u64)> = BinaryHeap::with_capacity(k + 1);

        for i in 0..n {
            let start = i * 128;
            let end = start + 128;
            let vec = &vectors[start..end];
            let dist_sq = l2_distance_squared(query, vec);

            if heap.len() < k {
                heap.push((OrderedFloat(dist_sq), ids[i]));
            } else if dist_sq < heap.peek().unwrap().0 .0 {
                heap.pop();
                heap.push((OrderedFloat(dist_sq), ids[i]));
            }
        }

        // Convert heap to sorted results (ascending by distance)
        let mut results: Vec<(u64, f64)> = heap
            .into_iter()
            .map(|(OrderedFloat(dist_sq), id)| (id, (dist_sq as f64).sqrt()))
            .collect();

        results.sort_by(|a, b| a.1.partial_cmp(&b.1).unwrap());

        results
            .into_iter()
            .map(|(id, distance)| SearchResult { id, distance })
            .collect()
    }
}

// Wrapper for f32 to implement Ord for BinaryHeap (max-heap by default)
#[derive(PartialEq, PartialOrd)]
struct OrderedFloat(f32);

impl Eq for OrderedFloat {}

impl Ord for OrderedFloat {
    fn cmp(&self, other: &Self) -> std::cmp::Ordering {
        // Reverse order for max-heap behavior with smallest on top when we pop
        self.0.partial_cmp(&other.0).unwrap().reverse()
    }
}

use crate::api::SearchResult;
use crate::distance::{l2_distance, l2_distance_squared};
use rayon::prelude::*;
use std::sync::RwLock;

// Store vectors in a flat array for better cache locality
pub struct VectorDB {
    ids: RwLock<Vec<u64>>,
    vectors: RwLock<Vec<f32>>, // flattened: [v0_0, v0_1, ..., v0_127, v1_0, ...]
}

impl VectorDB {
    pub fn new() -> Self {
        VectorDB {
            ids: RwLock::new(Vec::new()),
            vectors: RwLock::new(Vec::new()),
        }
    }

    pub fn insert(&self, id: u64, vector: Vec<f32>) {
        let mut ids = self.ids.write().unwrap();
        let mut vectors = self.vectors.write().unwrap();
        ids.push(id);
        vectors.extend(vector);
    }

    pub fn bulk_insert(&self, vectors: Vec<(u64, Vec<f32>)>) -> usize {
        let mut ids = self.ids.write().unwrap();
        let mut vecs = self.vectors.write().unwrap();
        let count = vectors.len();
        for (id, v) in vectors {
            ids.push(id);
            vecs.extend(v);
        }
        count
    }

    pub fn search(&self, query: &[f32], top_k: u32) -> Vec<SearchResult> {
        let ids = self.ids.read().unwrap();
        let vectors = self.vectors.read().unwrap();

        let n = ids.len();
        if n == 0 {
            return Vec::new();
        }

        let k = top_k as usize;

        // Divide data into chunks for parallel processing
        // Each chunk finds its local top-k, then we merge
        let num_chunks = rayon::current_num_threads();
        let chunk_size = (n + num_chunks - 1) / num_chunks;

        let local_top_k: Vec<Vec<(u64, f32)>> = (0..num_chunks)
            .into_par_iter()
            .filter_map(|chunk_idx| {
                let start = chunk_idx * chunk_size;
                if start >= n {
                    return None;
                }
                let end = (start + chunk_size).min(n);

                // Find local top-k using a simple selection approach
                let mut local_results: Vec<(u64, f32)> = Vec::with_capacity(k);

                for i in start..end {
                    let vec_start = i * 128;
                    let vec_end = vec_start + 128;
                    let vec = &vectors[vec_start..vec_end];
                    let dist_sq = l2_distance_squared(query, vec);

                    if local_results.len() < k {
                        local_results.push((ids[i], dist_sq));
                        // Maintain sorted order for small k
                        local_results.sort_by(|a, b| a.1.partial_cmp(&b.1).unwrap());
                    } else if dist_sq < local_results[k - 1].1 {
                        local_results[k - 1] = (ids[i], dist_sq);
                        // Re-sort the last element into place
                        local_results.sort_by(|a, b| a.1.partial_cmp(&b.1).unwrap());
                    }
                }

                Some(local_results)
            })
            .collect();

        // Merge all local top-k results
        let mut all_results: Vec<(u64, f32)> = local_top_k.into_iter().flatten().collect();

        // Final sort and take top k
        all_results.sort_by(|a, b| a.1.partial_cmp(&b.1).unwrap());
        all_results.truncate(k);

        // Convert to final results with actual L2 distance
        all_results
            .into_iter()
            .map(|(id, dist_sq)| SearchResult { 
                id, 
                distance: (dist_sq as f64).sqrt() 
            })
            .collect()
    }
}

use crate::api::SearchResult;
