use rayon::prelude::*;
use std::sync::Arc;

// Store vectors in a flat array for better cache locality
// Use Arc for lock-free reads after initialization
pub struct VectorDB {
    data: Arc<VectorData>,
}

struct VectorData {
    ids: Vec<u64>,
    vectors: Vec<f32>, // flattened: [v0_0, v0_1, ..., v0_127, v1_0, ...]
}

impl VectorDB {
    pub fn new() -> Self {
        VectorDB {
            data: Arc::new(VectorData {
                ids: Vec::new(),
                vectors: Vec::new(),
            }),
        }
    }

    pub fn insert(&self, id: u64, vector: Vec<f32>) {
        // For single insert, we need to clone and replace
        let mut new_data = (*self.data).clone();
        new_data.ids.push(id);
        new_data.vectors.extend(vector);
        self.data = Arc::new(new_data);
    }

    pub fn bulk_insert(&self, vectors: Vec<(u64, Vec<f32>)>) -> usize {
        let count = vectors.len();
        let mut new_ids = self.data.ids.clone();
        let mut new_vectors = self.data.vectors.clone();

        for (id, v) in vectors {
            new_ids.push(id);
            new_vectors.extend(v);
        }

        self.data = Arc::new(VectorData {
            ids: new_ids,
            vectors: new_vectors,
        });
        count
    }

    pub fn search(&self, query: &[f32], top_k: u32) -> Vec<SearchResult> {
        let n = self.data.ids.len();
