use std::arch::x86_64::*;

#[inline]
pub fn l2_distance_squared(a: &[f32], b: &[f32]) -> f32 {
    debug_assert_eq!(a.len(), 128);
    debug_assert_eq!(b.len(), 128);

    unsafe {
        // Use AVX2 to process 8 floats at a time
        let mut acc0 = _mm256_setzero_ps();
        let mut acc1 = _mm256_setzero_ps();
        let mut acc2 = _mm256_setzero_ps();
        let mut acc3 = _mm256_setzero_ps();

        // Process 32 floats per iteration (4 x 8)
        for i in (0..128).step_by(32) {
            // Load 8 floats from each vector
            let a0 = _mm256_loadu_ps(a.as_ptr().add(i));
            let b0 = _mm256_loadu_ps(b.as_ptr().add(i));
            let diff0 = _mm256_sub_ps(a0, b0);
            acc0 = _mm256_fmadd_ps(diff0, diff0, acc0);

            let a1 = _mm256_loadu_ps(a.as_ptr().add(i + 8));
            let b1 = _mm256_loadu_ps(b.as_ptr().add(i + 8));
            let diff1 = _mm256_sub_ps(a1, b1);
            acc1 = _mm256_fmadd_ps(diff1, diff1, acc1);

            let a2 = _mm256_loadu_ps(a.as_ptr().add(i + 16));
            let b2 = _mm256_loadu_ps(b.as_ptr().add(i + 16));
            let diff2 = _mm256_sub_ps(a2, b2);
            acc2 = _mm256_fmadd_ps(diff2, diff2, acc2);

            let a3 = _mm256_loadu_ps(a.as_ptr().add(i + 24));
            let b3 = _mm256_loadu_ps(b.as_ptr().add(i + 24));
            let diff3 = _mm256_sub_ps(a3, b3);
            acc3 = _mm256_fmadd_ps(diff3, diff3, acc3);
        }

        // Sum all accumulators
        let sum0 = _mm256_add_ps(acc0, acc1);
        let sum1 = _mm256_add_ps(acc2, acc3);
        let sum = _mm256_add_ps(sum0, sum1);

        // Horizontal sum
        let sum256 = _mm256_hadd_ps(sum, sum);
        let sum256 = _mm256_hadd_ps(sum256, sum256);

        let lo = _mm256_extractf128_ps(sum256, 0);
        let hi = _mm256_extractf128_ps(sum256, 1);
        let final_sum = _mm_add_ps(lo, hi);
        let final_sum = _mm_hadd_ps(final_sum, final_sum);
        let final_sum = _mm_hadd_ps(final_sum, final_sum);

        _mm_cvtss_f32(final_sum)
    }
}

#[inline]
pub fn l2_distance(a: &[f32], b: &[f32]) -> f64 {
    (l2_distance_squared(a, b) as f64).sqrt()
}

#[inline]
pub fn l2_distance_squared(a: &[f32], b: &[f32]) -> f32 {
    debug_assert_eq!(a.len(), 128);
    debug_assert_eq!(b.len(), 128);

    let mut sum0: f32 = 0.0;
    let mut sum1: f32 = 0.0;
    let mut sum2: f32 = 0.0;
    let mut sum3: f32 = 0.0;
    let mut sum4: f32 = 0.0;
    let mut sum5: f32 = 0.0;
    let mut sum6: f32 = 0.0;
    let mut sum7: f32 = 0.0;

    // Unroll loop 8x for 128 elements (128 / 8 = 16 iterations)
    for i in (0..128).step_by(8) {
        let d0 = a[i] - b[i];
        let d1 = a[i + 1] - b[i + 1];
        let d2 = a[i + 2] - b[i + 2];
        let d3 = a[i + 3] - b[i + 3];
        let d4 = a[i + 4] - b[i + 4];
        let d5 = a[i + 5] - b[i + 5];
        let d6 = a[i + 6] - b[i + 6];
        let d7 = a[i + 7] - b[i + 7];

        sum0 += d0 * d0;
        sum1 += d1 * d1;
        sum2 += d2 * d2;
        sum3 += d3 * d3;
        sum4 += d4 * d4;
        sum5 += d5 * d5;
        sum6 += d6 * d6;
        sum7 += d7 * d7;
    }

    sum0 + sum1 + sum2 + sum3 + sum4 + sum5 + sum6 + sum7
}

#[inline]
pub fn l2_distance(a: &[f32], b: &[f32]) -> f64 {
    (l2_distance_squared(a, b) as f64).sqrt()
}

